// Meyvə səbətini yoxlayırıq
const fruits = ["alma", "banan", "portağal"];
for (let fruit of fruits) {
  console.log("Meyvə: " + fruit);
}
// nəticə:
// Meyvə: alma
// Meyvə: banan
// Meyvə: portağal

// Sətirdəki hərfləri yoxlayırıq
const word = "salam";
for (let letter of word) {
  console.log("Hərf: " + letter);
}
// nəticə:
// Hərf: s
// Hərf: a
// Hərf: l
// Hərf: a
// Hərf: m

// Blok scope ilə nümunə
for (let item of ["bir", "iki"]) {
  let message = "Element: " + item;
  console.log(message);
}
// nəticə: Element: bir, Element: iki
// console.log(message); // Xəta: message is not defined

// Müqayisə nümunəsi
const fruits = ["alma", "banan"];
for (let fruit of fruits) {
  console.log("for...of: " + fruit);
}
// nəticə: for...of: alma, for...of: banan

const obj = { a: "alma", b: "banan" };
for (let key in obj) {
  console.log("for...in: " + key + " -> " + obj[key]);
}
// nəticə: for...in: a -> alma, for...in: b -> banan

