// Check a fruit basket
const fruits = ["apple", "banana", "orange"];
for (let fruit of fruits) {
  console.log("Fruit: " + fruit);
}
// Output:
// Fruit: apple
// Fruit: banana
// Fruit: orange

// Check letters in a string
const word = "hello";
for (let letter of word) {
  console.log("Letter: " + letter);
}
// Output:
// Letter: h
// Letter: e
// Letter: l
// Letter: l
// Letter: o

// Block scope example
for (let item of ["one", "two"]) {
  let message = "Element: " + item;
  console.log(message);
}
// Output: Element: one, Element: two
// console.log(message); // Error: message is not defined

// Comparison example
const fruits = ["apple", "banana"];
for (let fruit of fruits) {
  console.log("for...of: " + fruit);
}
// Output: for...of: apple, for...of: banana

const obj = { a: "apple", b: "banana" };
for (let key in obj) {
  console.log("for...in: " + key + " -> " + obj[key]);
}
// Output: for...in: a -> apple, for...in: b -> banana

