// Проверяем корзину с фруктами
const fruits = ["яблоко", "банан", "апельсин"];
for (let fruit of fruits) {
  console.log("Фрукт: " + fruit);
}
// Вывод:
// Фрукт: яблоко
// Фрукт: банан
// Фрукт: апельсин

// Проверяем буквы в строке
const word = "привет";
for (let letter of word) {
  console.log("Буква: " + letter);
}
// Вывод:
// Буква: п
// Буква: р
// Буква: и
// Буква: в
// Буква: е
// Буква: т

// Пример блочной области видимости
for (let item of ["один", "два"]) {
  let message = "Элемент: " + item;
  console.log(message);
}
// Вывод: Элемент: один, Элемент: два
// console.log(message); // Ошибка: message не определена

// Пример сравнения
const fruits = ["яблоко", "банан"];
for (let fruit of fruits) {
  console.log("for...of: " + fruit);
}
// Вывод: for...of: яблоко, for...of: банан

const obj = { a: "яблоко", b: "банан" };
for (let key in obj) {
  console.log("for...in: " + key + " -> " + obj[key]);
}
// Вывод: for...in: a -> яблоко, for...in: b -> банан

